const input = $input.first().json;
const order = input.body ?? input;
const billing = order.billing;

if (!billing?.email) {
  throw new Error('Order has no billing email');
}

return [{
  json: {
    order,
    person: {
      wooCustomerId: order.customer_id
        ? String(order.customer_id)
        : null,
      email: billing.email.trim().toLowerCase(),
      firstName: billing.first_name || '',
      lastName: billing.last_name || '',
    },
  },
}];

const input = $input.first().json;
const p = input.person ?? input;

const query = `mutation {
  createPeople(
    data: [{
      wooCustomerId: ${JSON.stringify(p.wooCustomerId)}
      emails: {
        primaryEmail: ${JSON.stringify(p.email)}
        additionalEmails: []
      }
      name: {
        firstName: ${JSON.stringify(p.firstName)}
        lastName: ${JSON.stringify(p.lastName)}
      }
    }]
    upsert: true
  ) {
    id
    wooCustomerId
    emails {
      primaryEmail
    }
  }
}`;

return [{ json: { ...input, query } }];

const response = $input.first().json;
const context = $('Prepare Person').first().json;
const person = response.data?.createPeople?.[0];

if (!person?.id) {
  throw new Error('Twenty did not return a Person ID');
}

return [{
  json: {
    order: context.order,
    person: context.person,
    personId: person.id,
    twentyPerson: person,
  },
}];

const current = $input.first().json;
const order = current.order;

if (!Array.isArray(order.line_items) || !order.line_items.length) {
  throw new Error('Order has no line items');
}

const productsById = new Map();

for (const item of order.line_items) {
  const wooCatalogId = String(item.variation_id || item.product_id);

  productsById.set(wooCatalogId, {
    wooCatalogId,
    parentWooProductId: item.variation_id ? String(item.product_id) : null,
    name: item.name,
    sku: item.sku || '',
    description: String(item.product_description ?? ''),
    currentPrice: Number(item.price ?? item.total / (item.quantity || 1)),
    currency: order.currency,
  });
}

return [{
  json: {
    ...current,
    order,
    products: [...productsById.values()],
  },
}];

const input = $input.first().json;

const rows = input.products.map(product => {
  const price = Number(product.currentPrice);

  if (!product.wooCatalogId || !Number.isFinite(price)) {
    throw new Error('Product has an invalid ID or price');
  }

  return `{
    wooCatalogId: ${JSON.stringify(product.wooCatalogId)}
    parentWooProductId: ${JSON.stringify(product.parentWooProductId)}
    name: ${JSON.stringify(product.name)}
    sku: ${JSON.stringify(product.sku)}
    description: ${JSON.stringify(product.description)}
    currentPrice: ${price}
  }`;
}).join(',');

const query = `mutation {
  createProducts(
    data: [${rows}]
    upsert: true
  ) {
    id
    wooCatalogId
    name
    currentPrice
  }
}`;

return [{ json: { ...input, query } }];

const response = $input.first().json;
const products = response.data?.createProducts;
const wooOrder = $('Prepare Products').first().json.order;
const personId = $('Extract Person ID').first().json.personId;

if (!products?.length || !personId) {
  throw new Error('Missing Product or Person IDs');
}

const total = Number(wooOrder.total);
const rawDate = wooOrder.date_completed_gmt;

if (!Number.isFinite(total) || !rawDate) {
  throw new Error('Order has an invalid total or completion date');
}

const completedAt = new Date(
  rawDate.endsWith('Z') ? rawDate : `${rawDate}Z`
).toISOString();

const query = `mutation {
  createOrders(
    data: [{
      wooOrderId: ${JSON.stringify(String(wooOrder.id))}
      orderNumber: ${JSON.stringify(String(wooOrder.number))}
      name: ${JSON.stringify(`Order ${wooOrder.number}`)}
      total: ${total}
      currencyCustom: ${JSON.stringify(wooOrder.currency)}
      completedAt: ${JSON.stringify(completedAt)}
      syncStatus: SYNCING
      customer: {
        connect: {
          where: { id: ${JSON.stringify(personId)} }
        }
      }
    }]
    upsert: true
  ) {
    id
    wooOrderId
    syncStatus
    customer {
      id
    }
  }
}`;

return [{
  json: {
    wooOrder,
    personId,
    productIds: Object.fromEntries(
      products.map(product => [
        product.wooCatalogId,
        product.id,
      ])
    ),
    query,
  },
}];

const response = $input.first().json;
const orderRecord = response.data?.createOrders?.[0];
const context = $('Build Order Mutation').first().json;
const { wooOrder, productIds } = context;

if (!orderRecord?.id) {
  throw new Error('Missing Twenty Order ID');
}

const rows = wooOrder.line_items.map(item => {
  const catalogId = String(item.variation_id || item.product_id);
  const productId = productIds[catalogId];

  if (!productId) {
    throw new Error(`Missing Product ID for ${catalogId}`);
  }

  const metadata = item.meta_data ?? [];

  const addOnLabels = new Set(
    metadata
      .filter(meta => meta.key === '_wapf_meta')
      .flatMap(meta => Object.values(meta.value ?? {}))
      .map(value => value?.label)
      .filter(Boolean)
  );

  const visibleMetadata = metadata.filter(
    meta => !String(meta.key).startsWith('_')
  );

  const format = meta => ({
    name: meta.display_key ?? meta.key,
    value: meta.display_value ?? meta.value,
  });

  const addOns = visibleMetadata
    .filter(meta =>
      addOnLabels.has(meta.key) ||
      addOnLabels.has(meta.display_key)
    )
    .map(format);

  const variations = item.variation_id
    ? visibleMetadata
        .filter(meta =>
          !addOnLabels.has(meta.key) &&
          !addOnLabels.has(meta.display_key)
        )
        .map(format)
    : [];

  return `{
    name: ${JSON.stringify(`#${wooOrder.number} - ${item.name}`)}
    wooLineItemKey: ${JSON.stringify(`${wooOrder.id}:${item.id}`)}
    productNameSnapshot: ${JSON.stringify(item.name)}
    skuSnapshot: ${JSON.stringify(item.sku || '')}
    quantity: ${Number(item.quantity)}
    unitPriceSnapshot: ${Number(item.price)}
    lineTotal: ${Number(item.total)}
    variationSnapshot: ${JSON.stringify(JSON.stringify(variations))}
    addOnsSnapshot: ${JSON.stringify(JSON.stringify(addOns))}
    order: {
      connect: { where: { id: ${JSON.stringify(orderRecord.id)} } }
    }
    product: {
      connect: { where: { id: ${JSON.stringify(productId)} } }
    }
  }`;
}).join(',');

const query = `mutation {
  createOrderItems(
    data: [${rows}]
    upsert: true
  ) {
    id
    wooLineItemKey
    order { id }
    product { id }
  }
}`;

return [{
  json: {
    ...context,
    orderId: orderRecord.id,
    query,
  },
}];

const response = $input.first().json;
const items = response.data?.createOrderItems;
const context = $('Build Order Items Mutation').first().json;

if (!items?.length || !context.orderId) {
  throw new Error('Missing Order or Order Item IDs');
}

const query = `mutation {
  updateOrder(
    id: ${JSON.stringify(context.orderId)}
    data: { syncStatus: COMPLETED }
  ) {
    id
    wooOrderId
    syncStatus
  }
}`;

return [{
  json: {
    ...context,
    orderItemIds: items.map(item => item.id),
    query,
  },
}];
